# Flexible *args and **kwargs Wrapper Pattern
def log_call(func):
    def wrapper(*args, **kwargs):
        print(f'Calling {func.__name__} with args={args}, kwargs={kwargs}')
        return func(*args, **kwargs)
    return wrapper

@log_call
def multiply(a, b=1):
    return a * b

multiply(5, b=3)
